			<u-empty :show="goods_list.length == 0" mode="list"></u-empty>

			<view v-if="goods_list.length > 0" style="padding-top: 10px;padding-bottom: 10px;">
				<u-loadmore :status="status" :icon-type="iconType" :load-text="loadText" />
