<script>
	import MinLevelPrice from '@/components/min-level-price'
	export default {
		components: {
			MinLevelPrice
		},
		data() {
			return {



				keyword: '',
				keyword_type: 1,
				goods_list: [],
				page: 1,
				limit: 10,

				status: 'loadmore',
				iconType: 'flower',
				loadText: {
					loadmore: '轻轻上拉',
					loading: '努力加载中',
					nomore: '实在没有了'
				}
			}
		},
		computed: {

		},
		onLoad(e) {
			const {
				keyword
			} = this.$Route.query
			let that = this

			this.keyword = keyword
			//历史搜索列表

			this.loadData();
		},
		methods: {
			goto(path, query) {
				this.$Router.push({
					path,
					query
				})
			},
			//排序
			clickSearch(keyword_type) {
				this.page = 1;
				switch (keyword_type) {
					case 3: //价格
						if (this.keyword_type == 3) {
							this.keyword_type = 4;
						} else {
							this.keyword_type = 3;
						}
						break;
					default:
						this.keyword_type = keyword_type
				}
				this.goods_list = []
				this.page = 1;
				this.loadData()
			},
			//查询数据
			async loadData() {
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})


				var search_num_time = 0
				//是否增加搜索次数
				uni.getStorage({
					key: 'search_num_time',
					success: (res) => {

						search_num_time = res.data
						uni.removeStorage({
							key: 'search_num_time'
						})
					},
				});

				await this.$u.api.search({
					page: this.page,
					limit: this.limit,
					keyword: this.keyword,
					keyword_type: this.keyword_type,
					s_t: search_num_time,
				}).then((res) => {

					if (res.length == 0) {
						this.status = 'nomore'
					} else {
						if (this.goods_list.length > 0) {
							this.goods_list = this.goods_list.concat(res)
						} else {
							this.goods_list = res
						}

						if (res.length < this.limit) {
							this.status = 'nomore'
						} else {
							this.status = 'loadmore'
						}

					}
				}).catch((res) => {

				})
				uni.hideLoading()

			},
			//滑动加载
			lower(e) {
				this.page++
				this.loadData()
			}
		}
	}
</script>
