<template>
	<view v-if="viewMinGoodsPrice" class="badge" :class="[badgeClassName]">
		<view class="wrap">
			最低价<template v-if="showPrice">￥{{ price2 }}</template>
		</view>
	</view>
</template>

<script>
	import _ from 'lodash'
	import {
		mapGetters
	} from 'vuex'
	export default {
		components: {

		},
		props: {
			// 展示样式
			type: {
				type: Number,
				default: 0
			},
			price1: {
				type: [Number, String],
				default: 0
			},
			price2: {
				type: [Number, String],
				default: 0
			}
		},
		computed: {
			...mapGetters({
				viewMinGoodsPrice: 'viewMinGoodsPrice'
			}),
			badgeClassName() {
				return `badge-style-${this.type}`
			},
			showPrice() {
				return _.isEqual(this.price1 - 0, this.price2 - 0) ? false : true
			}
		},
		mounted() {

		}
	}
</script>

<style scoped lang="scss" scoped>
	.badge {
		width: 100%;

		.wrap {
			display: inline-block;
			background-color: #FF2121;
			color: #fff;
			border-radius: 10rpx;
			white-space: nowrap;
			font-size: 12px;
			line-height: 14px;
			padding: 4px 10px;
		}
	}
</style>